select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v where p.id = pl.postid and p.id = v.postid and p.id = ph.postid and p.id = c.postid and c.creationdate>=timestamp '2010-08-01 12:12:41' and p.score<=44 and p.favoritecount>=0 and p.favoritecount<=3 and p.creationdate>=timestamp '2010-08-11 13:53:56' and p.creationdate<=timestamp '2014-09-03 11:52:36' and pl.linktypeid=1 and pl.creationdate<=timestamp '2014-08-11 17:26:31' and ph.creationdate>=timestamp '2010-09-20 19:11:45' and v.creationdate<=timestamp '2014-09-11 00:00:00';
